@namespace Lumeo
@typeparam TItem

<div class="relative w-full overflow-auto" @attributes="AdditionalAttributes">
    @* role="grid" + aria-row/colcount give AT the table's shape. aria-rowcount
       includes the header row (+1). aria-multiselectable is only set when the
       selection checkboxes are present. Consumer-supplied <th>/<td> in the
       Header/Row templates keep their native table semantics; we add row/cell
       roles on the markup we own (rows + the selection column). *@
    <table class="@CssClass"
           role="grid"
           aria-rowcount="@(_itemsList.Count + 1)"
           aria-colcount="@(AriaColCount > 0 ? AriaColCount : null)"
           aria-multiselectable="@(Selectable ? "true" : null)">
        <thead class="[&_tr]:border-b [&_tr]:border-border/40" role="rowgroup">
            <tr class="border-b border-border/40 transition-colors hover:bg-muted/50" role="row" aria-rowindex="1">
                @if (Selectable)
                {
                    <th class="h-10 w-10 px-2 text-left align-middle font-medium text-muted-foreground" role="columnheader" scope="col">
                        <Checkbox Checked="@IsAllSelected" IsIndeterminate="@IsSomeSelected" CheckedChanged="@ToggleSelectAll" AriaLabel="Select all rows" />
                    </th>
                }
                @HeaderTemplate
            </tr>
        </thead>
        <tbody class="[&_tr:last-child]:border-0" role="rowgroup">
            @if (IsLoading)
            {
                @for (var i = 0; i < SkeletonRows; i++)
                {
                    <tr class="border-b border-border/40" role="row" aria-hidden="true">
                        @LoadingTemplate
                    </tr>
                }
            }
            else if (Items is null || !Items.Any())
            {
                <tr role="row">
                    <td colspan="100" class="p-8" role="gridcell">
                        @if (EmptyTemplate is not null)
                        {
                            @EmptyTemplate
                        }
                        else
                        {
                            <div class="flex flex-col items-center justify-center py-8 text-center">
                                <p class="text-sm text-muted-foreground">No results.</p>
                            </div>
                        }
                    </td>
                </tr>
            }
            else if (Virtualize)
            {
                <Microsoft.AspNetCore.Components.Web.Virtualization.Virtualize Items="@_itemsList" Context="item" SpacerElement="tr" ItemSize="@(ItemSize > 0 ? ItemSize : 41f)">
                    @* Keyed identically to the non-virtualized path so Blazor
                       diffs rows by identity, not position — without this the
                       virtualized rows were unkeyed and recycling reused the
                       wrong row state (checkbox/edit state) when scrolling. *@
                    <tr @key="DataGridRowKeys.KeyFor(item)" class="border-b border-border/40 transition-colors hover:bg-muted/50" role="row" aria-selected="@(Selectable ? (SelectedItems?.Contains(item) == true ? "true" : "false") : null)">
                        @if (Selectable)
                        {
                            <td class="w-10 px-2 py-2 align-middle" role="gridcell">
                                <Checkbox Checked="@(SelectedItems?.Contains(item) == true)" CheckedChanged="@(c => ToggleItem(item, c))" AriaLabel="Select row" />
                            </td>
                        }
                        @RowTemplate!(item)
                    </tr>
                </Microsoft.AspNetCore.Components.Web.Virtualization.Virtualize>
            }
            else
            {
                @foreach (var item in _itemsList)
                {
                    <tr @key="DataGridRowKeys.KeyFor(item)" class="border-b border-border/40 transition-colors hover:bg-muted/50" role="row" aria-selected="@(Selectable ? (SelectedItems?.Contains(item) == true ? "true" : "false") : null)">
                        @if (Selectable)
                        {
                            <td class="w-10 px-2 py-2 align-middle" role="gridcell">
                                <Checkbox Checked="@(SelectedItems?.Contains(item) == true)" CheckedChanged="@(c => ToggleItem(item, c))" AriaLabel="Select row" />
                            </td>
                        }
                        @RowTemplate!(item)
                    </tr>
                }
            }
        </tbody>
    </table>
</div>

@code {
    [Parameter] public IEnumerable<TItem>? Items { get; set; }
    [Parameter] public RenderFragment? HeaderTemplate { get; set; }
    [Parameter] public RenderFragment<TItem>? RowTemplate { get; set; }
    [Parameter] public RenderFragment? LoadingTemplate { get; set; }
    [Parameter] public RenderFragment? EmptyTemplate { get; set; }
    [Parameter] public bool IsLoading { get; set; }
    [Parameter] public int SkeletonRows { get; set; } = 5;
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    // Sorting
    [Parameter] public string? SortColumn { get; set; }
    [Parameter] public EventCallback<string?> SortColumnChanged { get; set; }
    [Parameter] public SortDirection SortDir { get; set; } = SortDirection.Ascending;
    [Parameter] public EventCallback<SortDirection> SortDirChanged { get; set; }
    [Parameter] public EventCallback<(string Column, SortDirection Direction)> OnSort { get; set; }

    // Selection
    [Parameter] public bool Selectable { get; set; }
    [Parameter] public HashSet<TItem>? SelectedItems { get; set; }
    [Parameter] public EventCallback<HashSet<TItem>> SelectedItemsChanged { get; set; }

    /// <summary>
    /// Total column count reported via <c>aria-colcount</c> on the grid
    /// (including the selection column when <see cref="Selectable"/> is on).
    /// Set this when the header/row templates render a fixed number of columns
    /// so assistive tech can announce "column X of N". 0 (default) omits the
    /// attribute since the count can't be inferred from consumer templates.
    /// </summary>
    [Parameter] public int AriaColCount { get; set; }

    // Virtualization
    /// <summary>Virtualize the row list using Blazor's &lt;Virtualize&gt; — only renders rows in the viewport.</summary>
    [Parameter] public bool Virtualize { get; set; }
    /// <summary>Estimated row height in pixels used by the virtualizer (default 41). Only relevant when <see cref="Virtualize"/> is true.</summary>
    [Parameter] public float ItemSize { get; set; } = 48;

    private string CssClass => $"w-full caption-bottom text-sm {Class}".Trim();

    // Cached per-render — recomputed in OnParametersSet to avoid repeated LINQ on every render pass.
    private List<TItem> _itemsList = [];
    private bool _isAllSelected;
    private bool _isSomeSelected;

    private bool IsAllSelected => _isAllSelected;
    private bool IsSomeSelected => _isSomeSelected;

    protected override void OnParametersSet()
    {
        _itemsList = Items?.ToList() ?? [];
        _isAllSelected = _itemsList.Count > 0 && SelectedItems is not null && _itemsList.All(i => SelectedItems.Contains(i));
        _isSomeSelected = SelectedItems is not null && SelectedItems.Count > 0 && !_isAllSelected;
    }

    // Selection mutations emit a NEW HashSet each time rather than mutating the
    // bound instance in place. Mutating-in-place broke `@bind-SelectedItems`:
    // the parent's field still pointed at the same reference, so SetParametersAsync
    // saw "no change" and downstream comparisons / change detection no-opped.
    // Returning a fresh set gives the callback a distinct identity per change —
    // the ref-stable contract two-way binding and EventCallback consumers expect.
    private async Task ToggleSelectAll(bool select)
    {
        if (Items is null) return;
        var next = select ? new HashSet<TItem>(Items) : new HashSet<TItem>();
        SelectedItems = next;
        RefreshSelectionCache();
        await SelectedItemsChanged.InvokeAsync(next);
    }

    private async Task ToggleItem(TItem item, bool selected)
    {
        var next = SelectedItems is null ? new HashSet<TItem>() : new HashSet<TItem>(SelectedItems);
        if (selected) next.Add(item);
        else next.Remove(item);
        SelectedItems = next;
        RefreshSelectionCache();
        await SelectedItemsChanged.InvokeAsync(next);
    }

    private void RefreshSelectionCache()
    {
        _isAllSelected = _itemsList.Count > 0 && SelectedItems is not null && _itemsList.All(i => SelectedItems.Contains(i));
        _isSomeSelected = SelectedItems is not null && SelectedItems.Count > 0 && !_isAllSelected;
    }

    public enum SortDirection { None, Ascending, Descending }
}

@namespace Lumeo

<th class="@CssClass" @attributes="AdditionalAttributes">
    <button type="button" class="inline-flex items-center gap-1 -ml-3 h-8 px-3 rounded-md hover:bg-accent hover:text-accent-foreground focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-2" @onclick="HandleSort">
        @ChildContent
        @if (SortColumn == Column)
        {
            @if (SortDirection == DataTable<object>.SortDirection.Ascending)
            {
                <Blazicon Svg="Lucide.ArrowUp" class="h-3.5 w-3.5" />
            }
            else if (SortDirection == DataTable<object>.SortDirection.Descending)
            {
                <Blazicon Svg="Lucide.ArrowDown" class="h-3.5 w-3.5" />
            }
            else
            {
                <Blazicon Svg="Lucide.ArrowUpDown" class="h-3.5 w-3.5 opacity-50" />
            }
        }
        else
        {
            <Blazicon Svg="Lucide.ArrowUpDown" class="h-3.5 w-3.5 opacity-50" />
        }
    </button>
</th>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter, EditorRequired] public string Column { get; set; } = "";
    [Parameter] public string? SortColumn { get; set; }
    [Parameter] public DataTable<object>.SortDirection SortDirection { get; set; }
    [Parameter] public EventCallback<(string Column, DataTable<object>.SortDirection Direction)> OnSort { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => $"h-10 px-2 text-left align-middle font-medium text-muted-foreground {Class}".Trim();

    private async Task HandleSort()
    {
        var newDirection = SortColumn == Column
            ? SortDirection switch
            {
                DataTable<object>.SortDirection.Ascending => DataTable<object>.SortDirection.Descending,
                DataTable<object>.SortDirection.Descending => DataTable<object>.SortDirection.None,
                _ => DataTable<object>.SortDirection.Ascending
            }
            : DataTable<object>.SortDirection.Ascending;

        await OnSort.InvokeAsync((Column, newDirection));
    }
}
